namespace
{

bool isInterfaceType(IRInst* inst)
{
    return as<IRInterfaceType>(inst) != nullptr;
}

bool hasInterfaceTypeArg(IRSpecialize* specialize)
{
    for (UInt ii = 0; ii < specialize->getArgCount(); ++ii)
    {
        if (isInterfaceType(specialize->getArg(ii)))
            return true;
    }
    return false;
}

bool containsByteAddressBufferLoadStore(IRInst* inst)
{
    switch (inst->getOp())
    {
    case kIROp_ByteAddressBufferLoad:
    case kIROp_ByteAddressBufferStore:
        return true;
    default:
        break;
    }

    for (auto child : inst->getDecorationsAndChildren())
    {
        if (containsByteAddressBufferLoadStore(child))
            return true;
    }
    return false;
}

IRInterfaceType* getByteAddressBufferInterfaceType(IRInst* inst)
{
    switch (inst->getOp())
    {
    case kIROp_ByteAddressBufferLoad:
        return as<IRInterfaceType>(inst->getDataType());

    case kIROp_ByteAddressBufferStore:
        return as<IRInterfaceType>(inst->getOperand(3)->getDataType());

    case kIROp_Call:
        {
            auto call = cast<IRCall>(inst);
            auto specialize = as<IRSpecialize>(call->getCallee());
            if (!specialize || !hasInterfaceTypeArg(specialize))
                return nullptr;

            if (!containsByteAddressBufferLoadStore(specialize->getBase()))
                return nullptr;

            for (UInt ii = 0; ii < specialize->getArgCount(); ++ii)
            {
                if (auto interfaceType = as<IRInterfaceType>(specialize->getArg(ii)))
                    return interfaceType;
            }
            return nullptr;
        }

    default:
        return nullptr;
    }
}

void diagnoseByteAddressBufferInterfaceTypesRec(IRInst* inst, DiagnosticSink* sink)
{
    if (auto interfaceType = getByteAddressBufferInterfaceType(inst))
    {
        sink->diagnose(Diagnostics::ByteAddressBufferInterfaceType{
            .type = interfaceType,
            .location = inst->sourceLoc,
        });
    }

    for (auto child : inst->getDecorationsAndChildren())
    {
        diagnoseByteAddressBufferInterfaceTypesRec(child, sink);
    }
}

} // namespace

void diagnoseByteAddressBufferInterfaceTypes(IRModule* module, DiagnosticSink* sink)
{
    if (!sink)
        return;

    diagnoseByteAddressBufferInterfaceTypesRec(module->getModuleInst(), sink);
}

