IRInterfaceType* getSpecializedInterfaceType(IRSpecialize* specialize, IRInst* type)
{
    if (auto interfaceType = as<IRInterfaceType>(type))
        return interfaceType;

    auto genericParam = as<IRParam>(type);
    auto generic = as<IRGeneric>(specialize->getBase());
    if (!genericParam || !generic)
        return nullptr;

    UInt argIndex = 0;
    for (auto param = generic->getFirstBlock()->getFirstParam(); param;
         param = param->getNextParam(), ++argIndex)
    {
        if (param != genericParam)
            continue;
        if (argIndex >= specialize->getArgCount())
            return nullptr;
        return as<IRInterfaceType>(specialize->getArg(argIndex));
    }
    return nullptr;
}

